mapper.update:
update file_import_record


    ext_field = #{extField},


    update_time = #{updateTime},


    updator_id = #{updatorId},


    updator = #{updator},


where
  tenant_id = #{tenantId}

    and create_time >= #{createDateStart}


    and create_time <= #{createDateEnd}

mapper.select:
select
DATE_FORMAT(create_time,'%Y-%m-%d') date,
from
file_import_record
where
  tenant_id = #{tenantId}
and
  deleted = 0

  and business_type = #{businessType}


  and process_status = #{processStatus}


  and ext_field = #{extField}


  and create_time >= #{createDateStart}


  and create_time <= #{createDateEnd}

order by create_time desc
